SELECT SUM(endowment) AS total_endowment
FROM institutions
WHERE accreditation_status = 'Accredited' AND type = 'Private';

SELECT academic_year, AVG(student_count) AS average_students_enrolled
FROM enrollment
GROUP BY academic_year;

SELECT research_topic, AVG(funding_amount) AS average_funding
FROM research
GROUP BY research_topic;

SELECT total_students
FROM institutions
WHERE location IN (SELECT city FROM locations WHERE state = 'NH');

SELECT AVG(acceptance_rate) AS average_acceptance_rate, SUM(applicants) AS total_applicants
FROM acceptance_rates
WHERE academic_year = '2022-2023';

SELECT acceptance_rate, applicants
FROM acceptance_rates
WHERE academic_year = '2022-2023';
